import json
import base64
import os
import time
import re

try:
    import requests
except Exception:
    requests = None


DEFAULT_TIMEOUT_SECS = float(os.environ.get("ENRICH_TIMEOUT_SECS", "1.0"))
MAX_URLS = int(os.environ.get("ENRICH_MAX_URLS", "3"))
MAX_RESP_BYTES = int(os.environ.get("ENRICH_MAX_RESP_BYTES", str(32 * 1024)))
MAX_TOTAL_BYTES = int(os.environ.get("ENRICH_MAX_TOTAL_BYTES", str(64 * 1024)))
ALLOWED_SCHEMES = tuple(os.environ.get("ENRICH_ALLOWED_SCHEMES", "https,http").split(","))
ALLOWED_HOSTS = [h.strip().lower() for h in os.environ.get("ENRICH_ALLOWED_HOSTS", "").split(",") if h.strip()]
USER_AGENT = os.environ.get("ENRICH_USER_AGENT", "lambda-edge-enricher/1.0")
HEADER_NAME = os.environ.get("ENRICH_HEADER_NAME", "x-enrich-url").lower()
OUT_HEADER_NAME = os.environ.get("ENRICH_OUT_HEADER_NAME", "x-enrich-context").lower()
OUT_STATUS_HEADER = os.environ.get("ENRICH_OUT_STATUS_HEADER", "x-enrich-status").lower()
PASS_THROUGH_HEADERS = [h.strip().lower() for h in os.environ.get("ENRICH_PASS_HEADERS", "").split(",") if h.strip()]
ALLOW_PRIVATE_IPS = os.environ.get("ENRICH_ALLOW_PRIVATE_IPS", "false").lower() in ("1", "true", "yes")


def _get_header_values(headers, name_lower):
    vals = headers.get(name_lower, [])
    out = []
    for item in vals:
        v = item.get("value")
        if v is not None:
            out.append(v)
    return out


def _set_single_header(headers, name_lower, value):
    headers[name_lower] = [{"key": name_lower, "value": value}]


def _del_header(headers, name_lower):
    if name_lower in headers:
        del headers[name_lower]


def _split_urls(raw_values):
    urls = []
    for raw in raw_values:
        if not raw:
            continue
        parts = re.split(r"[,\s]+", raw.strip())
        for p in parts:
            if p:
                urls.append(p)
    return urls


def _is_allowed_url(url):
    try:
        from urllib.parse import urlparse
        u = urlparse(url)
        if u.scheme.lower() not in ALLOWED_SCHEMES:
            return False
        if not u.netloc:
            return False
        host = (u.hostname or "").lower()
        if not host:
            return False
        if ALLOWED_HOSTS and host not in ALLOWED_HOSTS:
            return False
        if not ALLOW_PRIVATE_IPS:
            try:
                import ipaddress
                import socket
                ips = set()
                try:
                    ips.add(ipaddress.ip_address(host))
                except Exception:
                    try:
                        for res in socket.getaddrinfo(host, None):
                            ips.add(ipaddress.ip_address(res[4][0]))
                    except Exception:
                        pass
                for ip in ips:
                    if ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_multicast or ip.is_reserved:
                        return False
            except Exception:
                pass
        return True
    except Exception:
        return False


def _safe_bytes_content(resp):
    try:
        content = resp.content or b""
    except Exception:
        content = b""
    if len(content) > MAX_RESP_BYTES:
        content = content[:MAX_RESP_BYTES]
    return content


def _extract_payload(resp, content_bytes):
    ctype = (resp.headers.get("Content-Type") or "").split(";")[0].strip().lower()
    if ctype in ("application/json", "text/json"):
        try:
            return json.loads(content_bytes.decode("utf-8", errors="strict"))
        except Exception:
            try:
                return json.loads(content_bytes.decode("utf-8", errors="replace"))
            except Exception:
                return {"_raw_b64": base64.b64encode(content_bytes).decode("ascii"), "_content_type": ctype}
    if ctype.startswith("text/"):
        try:
            return content_bytes.decode("utf-8", errors="replace")
        except Exception:
            return base64.b64encode(content_bytes).decode("ascii")
    return {"_raw_b64": base64.b64encode(content_bytes).decode("ascii"), "_content_type": ctype}


def _make_requests_session():
    s = requests.Session()
    s.headers.update({"User-Agent": USER_AGENT})
    return s


def handler(event, context):
    cf = event["Records"][0]["cf"]
    request = cf["request"]
    headers = request.get("headers", {})

    raw_url_values = _get_header_values(headers, HEADER_NAME)
    urls = _split_urls(raw_url_values)[:MAX_URLS]

    if not urls:
        _del_header(headers, OUT_HEADER_NAME)
        _del_header(headers, OUT_STATUS_HEADER)
        request["headers"] = headers
        return request

    if requests is None:
        _set_single_header(headers, OUT_STATUS_HEADER, "error:requests_unavailable")
        _del_header(headers, OUT_HEADER_NAME)
        request["headers"] = headers
        return request

    sess = _make_requests_session()

    forwarded = {}
    for h in PASS_THROUGH_HEADERS:
        vals = _get_header_values(headers, h)
        if vals:
            forwarded[h] = ", ".join(vals)

    enrich = {"fetched": [], "errors": []}
    total_bytes = 0
    start = time.time()

    for url in urls:
        if time.time() - start > DEFAULT_TIMEOUT_SECS:
            enrich["errors"].append({"url": url, "error": "timeout_budget_exceeded"})
            continue

        if not _is_allowed_url(url):
            enrich["errors"].append({"url": url, "error": "url_not_allowed"})
            continue

        try:
            timeout = max(0.1, DEFAULT_TIMEOUT_SECS - (time.time() - start))
            r = sess.get(url, headers=forwarded, timeout=timeout, allow_redirects=True)
            content = _safe_bytes_content(r)
            total_bytes += len(content)
            if total_bytes > MAX_TOTAL_BYTES:
                enrich["errors"].append({"url": url, "error": "total_bytes_limit_exceeded"})
                break

            payload = _extract_payload(r, content)
            enrich["fetched"].append(
                {
                    "url": url,
                    "status_code": int(getattr(r, "status_code", 0) or 0),
                    "headers": {
                        "content_type": (r.headers.get("Content-Type") or ""),
                        "cache_control": (r.headers.get("Cache-Control") or ""),
                        "etag": (r.headers.get("ETag") or ""),
                    },
                    "data": payload,
                }
            )
        except Exception as e:
            enrich["errors"].append({"url": url, "error": str(e)[:300]})

    try:
        payload_json = json.dumps(enrich, separators=(",", ":"), ensure_ascii=False)
    except Exception:
        payload_json = json.dumps({"errors": [{"error": "serialization_failed"}]})

    b64 = base64.b64encode(payload_json.encode("utf-8")).decode("ascii")
    _set_single_header(headers, OUT_HEADER_NAME, b64)

    status = "ok"
    if enrich["errors"] and enrich["fetched"]:
        status = "partial"
    elif enrich["errors"] and not enrich["fetched"]:
        status = "error"
    _set_single_header(headers, OUT_STATUS_HEADER, status)

    request["headers"] = headers
    return request